class OrderTest extends TestCase {
    public function test_order_dispatches_correct_jobs(): void {
        Queue::fake();

        $this->actingAs($user)->postJson('/api/orders', $orderData);

        Queue::assertPushed(ProcessPayment::class, function ($job) use ($order) {
            return $job->orderId === $order->id;
        });
        Queue::assertPushedOn('payments', ProcessPayment::class);
        Queue::assertPushed(SendConfirmation::class);
        Queue::assertNotPushed(GenerateInvoice::class);
    }
}

